import{_ as a,o as t,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"📊 市場情緒日報 — 2026-05-02","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-02.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-02.md"}'),o={name:"Deep32Q知識庫/市場情緒/市場情緒_2026-05-02.md"};function n(i,e,l,h,c,p){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="📊-市場情緒日報-—-2026-05-02" tabindex="-1">📊 市場情緒日報 — 2026-05-02 <a class="header-anchor" href="#📊-市場情緒日報-—-2026-05-02" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026-05-02&quot;">​</a></h1><blockquote><p>掃描時間：2026-05-02 Asia/Taipei 10:37 搜尋工具：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🌍-全球財經頭條-5-條" tabindex="-1">🌍 全球財經頭條（5 條） <a class="header-anchor" href="#🌍-全球財經頭條-5-條" aria-label="Permalink to &quot;🌍 全球財經頭條（5 條）&quot;">​</a></h2><h3 id="_1-🇺🇸-apple-財報超預期-s-p-500-再創歷史新高" tabindex="-1">1. 🇺🇸 Apple 財報超預期，S&amp;P 500 再創歷史新高 <a class="header-anchor" href="#_1-🇺🇸-apple-財報超預期-s-p-500-再創歷史新高" aria-label="Permalink to &quot;1. 🇺🇸 Apple 財報超預期，S&amp;P 500 再創歷史新高&quot;">​</a></h3><p>蘋果發布財報優於預期，iPhone 17 熱賣及 MacBook Neo 供不應求，股價大漲。S&amp;P 500 和納斯達克持續創高，聯準會內部 8-4 投票分歧凸顯降息/升息不確定性。Meta 和 Microsoft 財報好壞參半。 <em>來源：ShareCafe (2026-05-02) — <a href="https://www.sharecafe.com.au/2026/05/02/central-banks-divide-as-oil-markets-roil-tech-posts-mixed-results/" target="_blank" rel="noreferrer">https://www.sharecafe.com.au/2026/05/02/central-banks-divide-as-oil-markets-roil-tech-posts-mixed-results/</a></em></p><h3 id="_2-🛢️-油價回落至-108-荷莫茲封閉效應仍主導" tabindex="-1">2. 🛢️ 油價回落至 $108，荷莫茲封閉效應仍主導 <a class="header-anchor" href="#_2-🛢️-油價回落至-108-荷莫茲封閉效應仍主導" aria-label="Permalink to &quot;2. 🛢️ 油價回落至 $108，荷莫茲封閉效應仍主導&quot;">​</a></h3><p>5/2 布蘭特 7 月期貨降至 <strong>$108.17/桶</strong>（WTI $101.94）。雖回落但仍為週線上漲。阿聯酋 5/1 退出 OPEC+，可能削弱 OPEC 影響力。大型油商領袖警告全球原油庫存逼近「懸崖邊緣」。 <em>來源：QNA (2026-05-02) — <a href="https://qna.org.qa/en/news/news-details?id=oil-prices-decline-at-settlement&amp;date=2/05/2026" target="_blank" rel="noreferrer">https://qna.org.qa/en/news/news-details?id=oil-prices-decline-at-settlement&amp;date=2/05/2026</a>, EnergyNewsBeat</em></p><h3 id="_3-🏛️-主要央行凍結利率-能源衝擊使前景不明" tabindex="-1">3. 🏛️ 主要央行凍結利率，能源衝擊使前景不明 <a class="header-anchor" href="#_3-🏛️-主要央行凍結利率-能源衝擊使前景不明" aria-label="Permalink to &quot;3. 🏛️ 主要央行凍結利率，能源衝擊使前景不明&quot;">​</a></h3><p>聯準會 8-4 投票分歧（4 票主張降息），鮑爾最後會議。英格蘭銀行維持 <strong>3.75%</strong>，歐洲央行維持 <strong>2.00%</strong>。凱文·沃什（Kevin Warsh）預計接任聯準會主席。日本當局黃金週可能干預匯市使日圓急升。 <em>來源：LiveSquawk (2026-05-02) — <a href="https://www.livesquawk.com/report/special_major-central-banks-pause-as-energy-shock-obscures-outlook" target="_blank" rel="noreferrer">https://www.livesquawk.com/report/special_major-central-banks-pause-as-energy-shock-obscures-outlook</a>, 經濟日報</em></p><h3 id="_4-🥇-金價回彈至-4-630-油價回落提供支撐" tabindex="-1">4. 🥇 金價回彈至 $4,630，油價回落提供支撐 <a class="header-anchor" href="#_4-🥇-金價回彈至-4-630-油價回落提供支撐" aria-label="Permalink to &quot;4. 🥇 金價回彈至 $4,630，油價回落提供支撐&quot;">​</a></h3><p>5/2 金價上漲至 <strong>$4,629.90/盎司</strong>（+0.68%），受益於油價回落和美元走弱。但週線仍跌約 2.3%。分析師預測年底目標 $5,400-$6,300。 <em>來源：TradingEconomics (2026-05-02) — <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/gold</a>, Morningstar</em></p><h3 id="_5-🇮🇳-s-p-500-創高、vix-續降至-16-8-市場情緒溫和樂觀" tabindex="-1">5. 🇮🇳 S&amp;P 500 創高、VIX 續降至 16.8，市場情緒溫和樂觀 <a class="header-anchor" href="#_5-🇮🇳-s-p-500-創高、vix-續降至-16-8-市場情緒溫和樂觀" aria-label="Permalink to &quot;5. 🇮🇳 S&amp;P 500 創高、VIX 續降至 16.8，市場情緒溫和樂觀&quot;">​</a></h3><p>VIX 恐慌指數跌至 <strong>16.8</strong>（前週 18.7），顯示市場恐慌情緒降溫。但地緣風險（荷莫茲）和通膨壓力仍構成主要不確定性。印度選舉結果公布在即。 <em>來源：Barchart (2026-05-02) — <a href="https://www.barchart.com/futures/quotes/VI*0" target="_blank" rel="noreferrer">https://www.barchart.com/futures/quotes/VI*0</a>, OptionCharts</em></p><hr><h2 id="🇹🇼-台灣財經頭條-5-條" tabindex="-1">🇹🇼 台灣財經頭條（5 條） <a class="header-anchor" href="#🇹🇼-台灣財經頭條-5-條" aria-label="Permalink to &quot;🇹🇼 台灣財經頭條（5 條）&quot;">​</a></h2><h3 id="_1-🤖-google-高層盛讚台灣-ai-供應鏈「極度完整」" tabindex="-1">1. 🤖 Google 高層盛讚台灣 AI 供應鏈「極度完整」 <a class="header-anchor" href="#_1-🤖-google-高層盛讚台灣-ai-供應鏈「極度完整」" aria-label="Permalink to &quot;1. 🤖 Google 高層盛讚台灣 AI 供應鏈「極度完整」&quot;">​</a></h3><p>Google 雲端平台研發總經理 Greg Moore 高度讚揚台灣從晶片設計、製造到系統整合的完整 AI 產業體系，肯定台積電在先進製程/封裝的領先地位及聯發科的研發能力。 <em>來源：TechNews (2026-05-02) — <a href="https://technews.tw/2026/05/02/greg-moore-praises-taiwan-ai-supply-chain/" target="_blank" rel="noreferrer">https://technews.tw/2026/05/02/greg-moore-praises-taiwan-ai-supply-chain/</a></em></p><h3 id="_2-📈-台經院-ai-熱潮非泡沫-可能延續-20-年" tabindex="-1">2. 📈 台經院：AI 熱潮非泡沫，可能延續 20 年 <a class="header-anchor" href="#_2-📈-台經院-ai-熱潮非泡沫-可能延續-20-年" aria-label="Permalink to &quot;2. 📈 台經院：AI 熱潮非泡沫，可能延續 20 年&quot;">​</a></h3><p>台灣經濟研究院指出台股此波漲勢由 AI 概念股驅動，並非泡沫，預估 AI 投資浪潮可能延續 20 年。但也提醒留意全球資金退潮風險。520 總統就職前五大信賴產業概念股有望受青睞。 <em>來源：TechNews (2026-04-24) — <a href="https://technews.tw/2026/04/24/ai-drives-taiwan-stocks-surge/" target="_blank" rel="noreferrer">https://technews.tw/2026/04/24/ai-drives-taiwan-stocks-surge/</a></em></p><h3 id="_3-🏭-鴻海-ai-伺服器市占率逾-4-成-營收年增-170" tabindex="-1">3. 🏭 鴻海 AI 伺服器市占率逾 4 成，營收年增 170% <a class="header-anchor" href="#_3-🏭-鴻海-ai-伺服器市占率逾-4-成-營收年增-170" aria-label="Permalink to &quot;3. 🏭 鴻海 AI 伺服器市占率逾 4 成，營收年增 170%&quot;">​</a></h3><p>鴻海在 AI 伺服器市場市佔率超過 40% 並持續擴大。雲端網路業務已超越消費電子成為集團最大事業體。蘋果財報亮眼亦使鴻海成為主要受惠者。 <em>來源：LTN (2026-05-02) — <a href="https://ec.ltn.com.tw/article/breakingnews/5422492" target="_blank" rel="noreferrer">https://ec.ltn.com.tw/article/breakingnews/5422492</a>, UDN</em></p><h3 id="_4-💾-全球-ai-伺服器年出貨成長-28-液冷滲透率上看-40" tabindex="-1">4. 💾 全球 AI 伺服器年出貨成長 28%，液冷滲透率上看 40% <a class="header-anchor" href="#_4-💾-全球-ai-伺服器年出貨成長-28-液冷滲透率上看-40" aria-label="Permalink to &quot;4. 💾 全球 AI 伺服器年出貨成長 28%，液冷滲透率上看 40%&quot;">​</a></h3><p>2026 年全球 AI 伺服器出貨量年成長率估達 28%，液冷技術滲透率今年將達 40%。摩根士丹利看好信驊等伺服器管理晶片廠，因生成式 AI 升級至代理式 AI（Agentic AI）將帶來新成長。 <em>來源：鉅亨網 (2026-05-02) — <a href="https://news.cnyes.com/news/id/6439014" target="_blank" rel="noreferrer">https://news.cnyes.com/news/id/6439014</a>, UDN</em></p><h3 id="_5-🇺🇸-alphabet-估值逼近-5-兆美元-分析師預測可能超越-nvidia" tabindex="-1">5. 🇺🇸 Alphabet 估值逼近 5 兆美元，分析師預測可能超越 NVIDIA <a class="header-anchor" href="#_5-🇺🇸-alphabet-估值逼近-5-兆美元-分析師預測可能超越-nvidia" aria-label="Permalink to &quot;5. 🇺🇸 Alphabet 估值逼近 5 兆美元，分析師預測可能超越 NVIDIA&quot;">​</a></h3><p>Alphabet 估值逼近 5 兆美元，分析師預測其 5 月中旬超越輝達（NVIDIA）成為全球最高市值公司的機率為 53%。三星半導體 4 奈米良率突破 80%，獲得 NVIDIA 投資的 Groq LPU 代工訂單。 <em>來源：Futunn (2026-05-02) — <a href="https://news.futunn.com/post/72465295" target="_blank" rel="noreferrer">https://news.futunn.com/post/72465295</a></em></p><hr><h2 id="📊-市場情緒判斷" tabindex="-1">📊 市場情緒判斷 <a class="header-anchor" href="#📊-市場情緒判斷" aria-label="Permalink to &quot;📊 市場情緒判斷&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">判斷</th><th style="text-align:left;">理由</th></tr></thead><tbody><tr><td style="text-align:center;">🟢 <strong>偏多</strong></td><td style="text-align:left;">S&amp;P 持續創高、Apple 財報優、AI 長線趨勢確立、油價小幅回落緩解壓力；但聯準會內部分歧、荷莫茲未解、資金輪動風險仍存。</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>web_search (2026-05-02): ShareCafe 全球市場 — <a href="https://www.sharecafe.com.au/2026/05/02/central-banks-divide-as-oil-markets-roil-tech-posts-mixed-results/" target="_blank" rel="noreferrer">https://www.sharecafe.com.au/2026/05/02/central-banks-divide-as-oil-markets-roil-tech-posts-mixed-results/</a></li><li>web_search (2026-05-02): QNA 油價回落 — <a href="https://qna.org.qa/en/news/news-details?id=oil-prices-decline-at-settlement&amp;date=2/05/2026" target="_blank" rel="noreferrer">https://qna.org.qa/en/news/news-details?id=oil-prices-decline-at-settlement&amp;date=2/05/2026</a></li><li>web_search (2026-05-02): LiveSquawk 央行政策 — <a href="https://www.livesquawk.com/report/special_major-central-banks-pause-as-energy-shock-obscures-outlook" target="_blank" rel="noreferrer">https://www.livesquawk.com/report/special_major-central-banks-pause-as-energy-shock-obscures-outlook</a></li><li>web_search (2026-05-02): TradingEconomics 金價 — <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/gold</a></li><li>web_search (2026-05-02): Barchart VIX — <a href="https://www.barchart.com/futures/quotes/VI*0" target="_blank" rel="noreferrer">https://www.barchart.com/futures/quotes/VI*0</a></li><li>web_search (2026-05-02): TechNews Google 讚台灣 AI — <a href="https://technews.tw/2026/05/02/greg-moore-praises-taiwan-ai-supply-chain/" target="_blank" rel="noreferrer">https://technews.tw/2026/05/02/greg-moore-praises-taiwan-ai-supply-chain/</a></li><li>web_search (2026-04-24): TechNews AI 非泡沫 — <a href="https://technews.tw/2026/04/24/ai-drives-taiwan-stocks-surge/" target="_blank" rel="noreferrer">https://technews.tw/2026/04/24/ai-drives-taiwan-stocks-surge/</a></li><li>web_search (2026-05-02): LTN 鴻海 AI 伺服器 — <a href="https://ec.ltn.com.tw/article/breakingnews/5422492" target="_blank" rel="noreferrer">https://ec.ltn.com.tw/article/breakingnews/5422492</a></li><li>web_search (2026-05-02): 鉅亨網 AI 伺服器 + 液冷 — <a href="https://news.cnyes.com/news/id/6439014" target="_blank" rel="noreferrer">https://news.cnyes.com/news/id/6439014</a></li><li>web_search (2026-05-02): Futunn Alphabet 估值 — <a href="https://news.futunn.com/post/72465295" target="_blank" rel="noreferrer">https://news.futunn.com/post/72465295</a></li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 抓取時間：2026-05-02 Asia/Taipei 10:37</em></p>',34)])])}const w=a(o,[["render",n]]);export{m as __pageData,w as default};
